function IsHasTask() return false end function TaskDialog() end
function GraceToExpDialog() this:AddTalk("关于文采值换经验：文采值换经验是为了使玩家在寓教娱乐的同时，也能达到升级的目的。每天玩家只能兑换一次经验。每次最多能兑换200文采值。") this:AddGraceChangeToExp("兑换") end
function MainDialog() this:AddTalk("科学技术是第一生产力。") this:AddTechResearcher("国王任免研究员(0)") this:AddTechUpdate("研究员升级科技(0)") this:AddTechBallot("国民科技投票(0)") this:AddGraceChangeToExp("文采值换经验") end this:PlaySound("20001.wav,20003.wav,20005.wav,61032.wav,61031.wav,61005.wav") this:AddDialog("MainDialog")

function MainDialog() if( IsHasTask() == false) then this:AddTalk(" 您好，我能为您做点什么？")
this:AddCloseItem("离开") end function Dialog1() this:AddTalk(" 打算在世外桃源安家了？真好啊！不过要想成为有房一族，你必须持有世外桃源的房契才行！现在我们这里所有的房产生意都被小金猪包揽了，房契的事儿，你得去找它！\n 如果你手上有兑换来的房契，同样要先找小金猪帮忙，打败飞天猪后拿到任务房契兑换一级房屋，然后就可以使用兑换得到的房契更换对应等级的房屋了~")
this:AddDialogItem("我还没有房契......","MainDialog") end function Dialog2() this:AddTalk(" 你可以将自己的房屋兑换成对应级别的房契，在兑换成房契后，你将会失去现有的房子。兑换非绑的房契将会花费相应的银子\n其中一级房屋不花费银子，二级房屋花费10锭银子，三级房花费50锭银子，四级房屋花费100锭银子，五级房花费200锭银子。")
end function Dialog3() this:AddTalk(" 现在你可以和你的朋友一起到其他人的房间一起休息，获得积分到世外桃源的货商处兑换奖励，每天最多获得30点的积分。如果你们的光临让房屋主人不开心，你可就有小麻烦了！") end TaskDialog() end this:AddDialog("MainDialog")
